/**
 * CSV Parser Library
 * Parses CSV strings into structured data with type coercion, error handling, and aggregation methods
 */

// Types and Interfaces
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Detects and converts value types
 */
function coerceValue(value: string): any {
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === "true") {
    return true;
  }
  if (value.toLowerCase() === "false") {
    return false;
  }

  // Check for number
  const numValue = Number(value);
  if (!isNaN(numValue) && value.trim() !== "") {
    return numValue;
  }

  // Default to string
  return value;
}

/**
 * Parses a single line of CSV, respecting quoted fields
 */
function parseCSVLine(
  line: string,
  delimiter: string = ",",
  quote: string = '"'
): string[] {
  const fields: string[] = [];
  let currentField = "";
  let insideQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quote) {
      if (insideQuotes && line[i + 1] === quote) {
        // Escaped quote (two quotes = one literal quote)
        currentField += quote;
        i += 2;
      } else {
        // Toggle quote state
        insideQuotes = !insideQuotes;
        i++;
      }
    } else if (char === delimiter && !insideQuotes) {
      // Found delimiter outside quotes
      fields.push(currentField);
      currentField = "";
      i++;
    } else {
      currentField += char;
      i++;
    }
  }

  // Push the last field
  fields.push(currentField);

  return fields;
}

/**
 * Main CSV parsing function
 */
export function parseCSV(
  input: string,
  options: CSVOptions = {}
): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const rows: Record<string, any>[] = [];
  const errors: ParseError[] = [];
  let headers: string[] = [];

  // Split input by line separator
  const lines = input.split(lineSeparator);

  // Process lines
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (line.trim() === "") {
      continue;
    }

    try {
      const fields = parseCSVLine(line, delimiter, quote);

      // First non-empty line becomes headers
      if (headers.length === 0) {
        headers = fields;
        continue;
      }

      // Validate row has correct number of columns
      if (fields.length !== headers.length) {
        errors.push({
          row: lineIndex,
          message: `Expected ${headers.length} columns but got ${fields.length}`,
        });
        continue;
      }

      // Create row object with type coercion
      const row: Record<string, any> = {};
      for (let i = 0; i < headers.length; i++) {
        row[headers[i]] = coerceValue(fields[i]);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: lineIndex,
        message: `Error parsing line: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  // Create result object with methods
  const result: CSVResult = {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          total += value;
        }
      }
      return total;
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let total = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          total += value;
          count++;
        }
      }

      if (count === 0) {
        return 0;
      }

      return total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      const groups = new Map<any, Record<string, any>[]>();

      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }

      return groups;
    },
  };

  return result;
}

/**
 * Comprehensive test suite for CSV Parser
 * Tests cover all features and edge cases
 */

import { parseCSV } from "./csv-parser";

// Test assertion helper
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string = ""): void {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expected}\nActual: ${actual}`
    );
  }
}

function assertDeepEquals<T>(actual: T, expected: T, message: string = ""): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertArrayEquals<T>(
  actual: T[],
  expected: T[],
  message: string = ""
): void {
  if (actual.length !== expected.length) {
    throw new Error(
      `Assertion failed: ${message}\nArray length mismatch. Expected: ${expected.length}, Actual: ${actual.length}`
    );
  }

  for (let i = 0; i < actual.length; i++) {
    if (JSON.stringify(actual[i]) !== JSON.stringify(expected[i])) {
      throw new Error(
        `Assertion failed: ${message}\nArray item at index ${i} mismatch.\nExpected: ${JSON.stringify(expected[i])}\nActual: ${JSON.stringify(actual[i])}`
      );
    }
  }
}

// ============================================================================
// TEST SUITE
// ============================================================================

console.log("🧪 Running CSV Parser Tests...\n");

// Test 1: Basic parsing
console.log("✓ Test 1: Basic parsing");
{
  const csv = `name,age,city
John,30,New York
Jane,25,London`;

  const result = parseCSV(csv);

  assertArrayEquals(result.headers, ["name", "age", "city"]);
  assertEquals(result.count(), 2, "Should have 2 rows");
  assertEquals(result.rows[0]["name"], "John", "First row name");
  assertEquals(result.rows[0]["age"], 30, "First row age as number");
  assertEquals(result.rows[1]["name"], "Jane", "Second row name");
  assertEquals(result.rows[1]["age"], 25, "Second row age as number");
}

// Test 2: Quoted fields with commas
console.log("✓ Test 2: Quoted fields with commas");
{
  const csv = `name,address,city
"Smith, John","123 Main St, Apt 4",Boston
"Doe, Jane","456 Oak Ave, Suite 200",Seattle`;

  const result = parseCSV(csv);

  assertEquals(
    result.rows[0]["name"],
    "Smith, John",
    "Should handle comma in quoted field"
  );
  assertEquals(
    result.rows[0]["address"],
    "123 Main St, Apt 4",
    "Should handle comma in address"
  );
  assertEquals(
    result.rows[1]["name"],
    "Doe, Jane",
    "Second row quoted field"
  );
}

// Test 3: Escaped quotes within quoted fields
console.log("✓ Test 3: Escaped quotes");
{
  const csv = `name,quote
"John ""The King"" Doe","He said ""Hello"""
"Jane Smith","She replied ""Hi"""`;

  const result = parseCSV(csv);

  assertEquals(
    result.rows[0]["name"],
    'John "The King" Doe',
    "Should unescape quotes in name"
  );
  assertEquals(
    result.rows[0]["quote"],
    'He said "Hello"',
    "Should unescape quotes in quote field"
  );
  assertEquals(
    result.rows[1]["name"],
    "Jane Smith",
    "Second row name"
  );
}

// Test 4: Custom delimiters
console.log("✓ Test 4: Custom delimiters");
{
  const csv = `name;age;city
John;30;New York
Jane;25;London`;

  const result = parseCSV(csv, { delimiter: ";" });

  assertArrayEquals(result.headers, ["name", "age", "city"]);
  assertEquals(result.rows[0]["name"], "John");
  assertEquals(result.rows[0]["city"], "New York");
}

// Test 5: Custom quote character
console.log("✓ Test 5: Custom quote character");
{
  const csv = `name,description
John,'Has, comma'
Jane,'Another, value'`;

  const result = parseCSV(csv, { quote: "'" });

  assertEquals(
    result.rows[0]["description"],
    "Has, comma",
    "Should handle custom quote"
  );
  assertEquals(result.rows[1]["description"], "Another, value");
}

// Test 6: Custom line separator
console.log("✓ Test 6: Custom line separator");
{
  const csv = `name,age,city|John,30,New York|Jane,25,London`;

  const result = parseCSV(csv, { lineSeparator: "|" });

  assertEquals(result.count(), 2);
  assertEquals(result.rows[0]["name"], "John");
  assertEquals(result.rows[1]["name"], "Jane");
}

// Test 7: Type coercion - numbers
console.log("✓ Test 7: Type coercion - numbers");
{
  const csv = `id,score,price
1,95.5,19.99
2,88.0,29.99
3,100,49.99`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["id"], 1, "Integer coercion");
  assertEquals(result.rows[0]["score"], 95.5, "Float coercion");
  assertEquals(result.rows[0]["price"], 19.99, "Price coercion");
  assertEquals(typeof result.rows[0]["id"], "number");
}

// Test 8: Type coercion - booleans
console.log("✓ Test 8: Type coercion - booleans");
{
  const csv = `name,active,premium
John,true,false
Jane,false,true
Bob,True,False`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["active"], true, "Lowercase true");
  assertEquals(result.rows[0]["premium"], false, "Lowercase false");
  assertEquals(result.rows[2]["active"], true, "Uppercase true");
  assertEquals(result.rows[2]["premium"], false, "Uppercase false");
  assertEquals(typeof result.rows[0]["active"], "boolean");
}

// Test 9: Type coercion - null values
console.log("✓ Test 9: Type coercion - null values");
{
  const csv = `name,age,notes
John,30,
Jane,,NULL
Bob,null,null`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["notes"], null, "Empty string to null");
  assertEquals(result.rows[1]["age"], null, "NULL to null");
  assertEquals(result.rows[1]["notes"], null, "NULL to null");
  assertEquals(result.rows[2]["age"], null, "null string to null");
  assertEquals(result.rows[2]["notes"], null, "null string to null");
}

// Test 10: Type coercion - strings
console.log("✓ Test 10: Type coercion - strings");
{
  const csv = `name,email,country
John,john@example.com,USA
Jane,jane@example.com,UK`;

  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0]["name"], "string");
  assertEquals(typeof result.rows[0]["email"], "string");
  assertEquals(result.rows[0]["email"], "john@example.com");
}

// Test 11: Malformed rows - column count mismatch
console.log("✓ Test 11: Malformed rows - column count mismatch");
{
  const csv = `name,age,city
John,30,New York
Jane,25
Bob,35,Chicago,USA`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, "Should skip malformed rows");
  assertEquals(result.errors.length, 2, "Should have 2 errors");
  assertEquals(
    result.errors[0].message,
    "Expected 3 columns but got 2",
    "Error message for insufficient columns"
  );
  assertEquals(
    result.errors[1].message,
    "Expected 3 columns but got 4",
    "Error message for excess columns"
  );
}

// Test 12: Filter functionality
console.log("✓ Test 12: Filter functionality");
{
  const csv = `name,age,city
John,30,New York
Jane,25,London
Bob,35,New York
Alice,28,Paris`;

  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 28);
  assertEquals(filtered.length, 2, "Should filter by age > 28");
  assertEquals(filtered[0]["name"], "John");
  assertEquals(filtered[1]["name"], "Bob");

  const byCity = result.filter((row) => row.city === "New York");
  assertEquals(byCity.length, 2, "Should filter by city");
  assertEquals(byCity[0]["name"], "John");
  assertEquals(byCity[1]["name"], "Bob");
}

// Test 13: Sum aggregation
console.log("✓ Test 13: Sum aggregation");
{
  const csv = `product,price,quantity
Apple,1.5,10
Banana,0.75,20
Orange,2.0,15`;

  const result = parseCSV(csv);

  const priceSum = result.sum("price");
  assertEquals(priceSum, 4.25, "Should sum prices correctly");

  const quantitySum = result.sum("quantity");
  assertEquals(quantitySum, 45, "Should sum quantities correctly");
}

// Test 14: Average aggregation
console.log("✓ Test 14: Average aggregation");
{
  const csv = `name,score
Alice,90
Bob,85
Charlie,95
Diana,100`;

  const result = parseCSV(csv);

  const average = result.average("score");
  assertEquals(average, 92.5, "Should calculate average correctly");
}

// Test 15: Count
console.log("✓ Test 15: Count");
{
  const csv = `id,name
1,Alice
2,Bob
3,Charlie`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3, "Should count rows correctly");
}

// Test 16: GroupBy aggregation
console.log("✓ Test 16: GroupBy aggregation");
{
  const csv = `city,person,age
New York,John,30
London,Jane,25
New York,Bob,35
London,Alice,28`;

  const result = parseCSV(csv);

  const grouped = result.groupBy("city");

  assertEquals(grouped.size, 2, "Should have 2 groups");
  assertEquals(
    grouped.get("New York")!.length,
    2,
    "Should have 2 people in New York"
  );
  assertEquals(grouped.get("London")!.length, 2, "Should have 2 people in London");
  assertEquals(grouped.get("New York")![0]["person"], "John");
  assertEquals(grouped.get("London")![0]["person"], "Jane");
}

// Test 17: Empty input
console.log("✓ Test 17: Empty input");
{
  const result = parseCSV("");

  assertEquals(result.headers.length, 0, "Should have no headers");
  assertEquals(result.count(), 0, "Should have no rows");
  assertEquals(result.errors.length, 0, "Should have no errors");
}

// Test 18: Single column
console.log("✓ Test 18: Single column");
{
  const csv = `name
Alice
Bob
Charlie`;

  const result = parseCSV(csv);

  assertArrayEquals(result.headers, ["name"]);
  assertEquals(result.count(), 3);
  assertEquals(result.rows[0]["name"], "Alice");
  assertEquals(result.rows[2]["name"], "Charlie");
}

// Test 19: Single row
console.log("✓ Test 19: Single row");
{
  const csv = `name,age,city
John,30,New York`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 1);
  assertEquals(result.rows[0]["name"], "John");
  assertEquals(result.rows[0]["age"], 30);
}

// Test 20: Headers with whitespace
console.log("✓ Test 20: Headers with whitespace");
{
  const csv = `name, age , city
John,30,New York`;

  const result = parseCSV(csv);

  // Headers should preserve exact format (including spaces)
  assertEquals(result.headers[1], " age ", "Header should preserve whitespace");
}

// Test 21: Very large field values
console.log("✓ Test 21: Very large field values");
{
  const longText = "A".repeat(10000);
  const csv = `id,description
1,"${longText}"
2,short`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["description"].length, 10000, "Should handle large fields");
  assertEquals(result.rows[0]["description"], longText);
}

// Test 22: Mixed quotes and commas
console.log("✓ Test 22: Mixed quotes and commas");
{
  const csv = `id,name,note
1,"Smith, Jr.","Quote: ""Hello, World!"""
2,Johnson,"No quotes"`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["name"], "Smith, Jr.");
  assertEquals(result.rows[0]["note"], 'Quote: "Hello, World!"');
  assertEquals(result.rows[1]["note"], "No quotes");
}

// Test 23: Empty quoted field
console.log("✓ Test 23: Empty quoted field");
{
  const csv = `name,middle,last
John,"",Smith
Jane,"M",Doe`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["middle"], null, "Empty quoted field becomes null");
  assertEquals(result.rows[1]["middle"], "M");
}

// Test 24: Numeric strings that look like numbers but should stay strings
console.log("✓ Test 24: Numeric strings");
{
  const csv = `zipcode,areacode,count
10001,212,100
92101,619,50`;

  const result = parseCSV(csv);

  // All should be coerced to numbers
  assertEquals(typeof result.rows[0]["zipcode"], "number");
  assertEquals(result.rows[0]["zipcode"], 10001);
}

// Test 25: Sum with non-numeric values
console.log("✓ Test 25: Sum with non-numeric values");
{
  const csv = `name,score
Alice,90
Bob,N/A
Charlie,85`;

  const result = parseCSV(csv);

  const sum = result.sum("score");
  assertEquals(sum, 175, "Should sum only numeric values");
}

// Test 26: Average with non-numeric values
console.log("✓ Test 26: Average with non-numeric values");
{
  const csv = `name,score
Alice,90
Bob,N/A
Charlie,100`;

  const result = parseCSV(csv);

  const avg = result.average("score");
  assertEquals(avg, 95, "Should average only numeric values (90+100)/2");
}

// Test 27: GroupBy with null values
console.log("✓ Test 27: GroupBy with null values");
{
  const csv = `category,value
A,10
,20
A,30`;

  const result = parseCSV(csv);

  const grouped = result.groupBy("category");

  assertEquals(grouped.size, 2, "Should have 2 groups (including null)");
  assertEquals(grouped.get("A")!.length, 2);
  assertEquals(grouped.get(null)!.length, 1);
}

// Test 28: Filter with complex conditions
console.log("✓ Test 28: Filter with complex conditions");
{
  const csv = `name,age,city,active
John,30,New York,true
Jane,25,London,false
Bob,35,New York,true
Alice,28,Paris,true`;

  const result = parseCSV(csv);

  const filtered = result.filter(
    (row) => row.active === true && row.city === "New York"
  );
  assertEquals(filtered.length, 2);
  assertEquals(filtered[0]["name"], "John");
  assertEquals(filtered[1]["name"], "Bob");
}

// Test 29: Trailing empty lines
console.log("✓ Test 29: Trailing empty lines");
{
  const csv = `name,age
John,30
Jane,25


`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 2, "Should ignore trailing empty lines");
}

// Test 30: Quote at end of field
console.log("✓ Test 30: Quote character handling");
{
  const csv = `name,description
John,"Simple field"
Jane,"Field with "" escaped quote"""`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["description"], "Simple field");
  assertEquals(result.rows[1]["description"], 'Field with " escaped quote"');
}

// Test 31: Multiple consecutive escaped quotes
console.log("✓ Test 31: Multiple consecutive escaped quotes");
{
  const csv = `text
"""""
""""""`; // Should parse as two quotes, then three quotes

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["text"], '""', "Two escaped quotes become two quotes");
  assertEquals(result.rows[1]["text"], '"""', "Three escaped quotes become three quotes");
}

// Test 32: Tab delimiter
console.log("✓ Test 32: Tab delimiter");
{
  const csv = `name\tage\tcity
John\t30\tNew York
Jane\t25\tLondon`;

  const result = parseCSV(csv, { delimiter: "\t" });

  assertEquals(result.rows[0]["name"], "John");
  assertEquals(result.rows[0]["age"], 30);
  assertEquals(result.rows[0]["city"], "New York");
}

// Test 33: Column not found error
console.log("✓ Test 33: Column not found error");
{
  const csv = `name,age
John,30`;

  const result = parseCSV(csv);

  try {
    result.sum("nonexistent");
    throw new Error("Should have thrown error for nonexistent column");
  } catch (e) {
    assert(
      e instanceof Error && e.message.includes("Column"),
      "Should throw error for nonexistent column in sum"
    );
  }

  try {
    result.average("nonexistent");
    throw new Error("Should have thrown error for nonexistent column");
  } catch (e) {
    assert(
      e instanceof Error && e.message.includes("Column"),
      "Should throw error for nonexistent column in average"
    );
  }

  try {
    result.groupBy("nonexistent");
    throw new Error("Should have thrown error for nonexistent column");
  } catch (e) {
    assert(
      e instanceof Error && e.message.includes("Column"),
      "Should throw error for nonexistent column in groupBy"
    );
  }
}

// Test 34: Only headers, no data rows
console.log("✓ Test 34: Only headers, no data rows");
{
  const csv = `name,age,city`;

  const result = parseCSV(csv);

  assertArrayEquals(result.headers, ["name", "age", "city"]);
  assertEquals(result.count(), 0);
}

// Test 35: Various number formats
console.log("✓ Test 35: Various number formats");
{
  const csv = `id,value,decimal
1,100,-50.5
2,-200,0.001
3,0,-0`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["id"], 1);
  assertEquals(result.rows[0]["value"], 100);
  assertEquals(result.rows[0]["decimal"], -50.5);
  assertEquals(result.rows[1]["value"], -200);
  assertEquals(result.rows[2]["decimal"], -0);
}

// Test 36: Whitespace-only fields
console.log("✓ Test 36: Whitespace-only fields");
{
  const csv = `name,middle
John,   
Jane, \t `;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["middle"], "   ", "Spaces should be preserved");
  assertEquals(result.rows[1]["middle"], " \t ", "Tabs should be preserved");
}

// Test 37: Special characters in fields
console.log("✓ Test 37: Special characters in fields");
{
  const csv = `name,symbol,emoji
John,"@#$%","😀👍"
Jane,"&*()",🎉`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["symbol"], "@#$%");
  assertEquals(result.rows[0]["emoji"], "😀👍");
  assertEquals(result.rows[1]["emoji"], "🎉");
}

// Test 38: Column header with special names
console.log("✓ Test 38: Column headers with special names");
{
  const csv = `id,value,total,sum,average
1,100,500,50,25`;

  const result = parseCSV(csv);

  assertEquals(result.rows[0]["id"], 1);
  assertEquals(result.rows[0]["value"], 100);
  // These should work fine - the method names don't conflict with data
}

// Test 39: Real-world example - sales data
console.log("✓ Test 39: Real-world example - sales data");
{
  const csv = `date,product,category,quantity,price,total
2024-01-01,"Widget A","Electronics",5,19.99,99.95
2024-01-02,"Gadget B","Tools",10,5.50,55.00
2024-01-03,"Component C","Electronics",3,45.00,135.00`;

  const result = parseCSV(csv);

  assertEquals(result.count(), 3);
  const electronicsSales = result.filter((row) => row.category === "Electronics");
  assertEquals(electronicsSales.length, 2);
  const totalRevenue = result.sum("total");
  assertEquals(totalRevenue, 289.95);
}

// Test 40: Empty CSV with just newline
console.log("✓ Test 40: Empty CSV with just newline");
{
  const result = parseCSV("\n");

  assertEquals(result.count(), 0);
  assertEquals(result.headers.length, 0);
}

console.log("\n✅ All 40 tests passed!");

/**
 * CSV Parser Library (JavaScript version)
 * Parses CSV strings into structured data with type coercion, error handling, and aggregation methods
 */

/**
 * Detects and converts value types
 */
function coerceValue(value) {
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === "true") {
    return true;
  }
  if (value.toLowerCase() === "false") {
    return false;
  }

  // Check for number
  const numValue = Number(value);
  if (!isNaN(numValue) && value.trim() !== "") {
    return numValue;
  }

  // Default to string
  return value;
}

/**
 * Parses a single line of CSV, respecting quoted fields
 */
function parseCSVLine(line, delimiter = ",", quote = '"') {
  const fields = [];
  let currentField = "";
  let insideQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quote) {
      if (insideQuotes && line[i + 1] === quote) {
        // Escaped quote (two quotes = one literal quote)
        currentField += quote;
        i += 2;
      } else {
        // Toggle quote state
        insideQuotes = !insideQuotes;
        i++;
      }
    } else if (char === delimiter && !insideQuotes) {
      // Found delimiter outside quotes
      fields.push(currentField);
      currentField = "";
      i++;
    } else {
      currentField += char;
      i++;
    }
  }

  // Push the last field
  fields.push(currentField);

  return fields;
}

/**
 * Main CSV parsing function
 */
function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const rows = [];
  const errors = [];
  let headers = [];

  // Split input by line separator
  const lines = input.split(lineSeparator);

  // Process lines
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (line.trim() === "") {
      continue;
    }

    try {
      const fields = parseCSVLine(line, delimiter, quote);

      // First non-empty line becomes headers
      if (headers.length === 0) {
        headers = fields;
        continue;
      }

      // Validate row has correct number of columns
      if (fields.length !== headers.length) {
        errors.push({
          row: lineIndex,
          message: `Expected ${headers.length} columns but got ${fields.length}`,
        });
        continue;
      }

      // Create row object with type coercion
      const row = {};
      for (let i = 0; i < headers.length; i++) {
        row[headers[i]] = coerceValue(fields[i]);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: lineIndex,
        message: `Error parsing line: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  // Create result object with methods
  const result = {
    rows,
    headers,
    errors,

    filter(predicate) {
      return rows.filter(predicate);
    },

    sum(column) {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          total += value;
        }
      }
      return total;
    },

    average(column) {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let total = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          total += value;
          count++;
        }
      }

      if (count === 0) {
        return 0;
      }

      return total / count;
    },

    count() {
      return rows.length;
    },

    groupBy(column) {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      const groups = new Map();

      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key).push(row);
      }

      return groups;
    },
  };

  return result;
}

// Export for Node.js
if (typeof module !== "undefined" && module.exports) {
  module.exports = { parseCSV };
}

