  return sum + ((p.stock || 0) * (p.price || 0));
}, 0);

console.log(`Total Units in Stock: ${totalInventory}`);
console.log(`Total Inventory Value: $${inventoryValue.toFixed(2)}`);

// Price statistics
const prices = activeProducts.map(p => p.price);
const avgPrice = prices.reduce((a, b) => a + b) / prices.length;
