// Test assertion helper
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string = ""): void {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expected}\nActual: ${actual}`
    );
  }
}

function assertDeepEquals<T>(actual: T, expected: T, message: string = ""): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertArrayEquals<T>(
  actual: T[],
  expected: T[],
  message: string = ""
): void {
  if (actual.length !== expected.length) {
    throw new Error(
      `Assertion failed: ${message}\nArray length mismatch. Expected: ${expected.length}, Actual: ${actual.length}`
    );
  }

  for (let i = 0; i < actual.length; i++) {
    if (JSON.stringify(actual[i]) !== JSON.stringify(expected[i])) {
      throw new Error(
        `Assertion failed: ${message}\nArray item at index ${i} mismatch.\nExpected: ${JSON.stringify(expected[i])}\nActual: ${JSON.stringify(actual[i])}`
      );
    }
  }
}

