/**
 * CSV Parser Library
 * Parses CSV strings into structured data with type coercion, error handling, and aggregation methods
 */

// Types and Interfaces
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Detects and converts value types
 */
function coerceValue(value: string): any {
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === "true") {
    return true;
  }
  if (value.toLowerCase() === "false") {
    return false;
  }

  // Check for number
  const numValue = Number(value);
  if (!isNaN(numValue) && value.trim() !== "") {
    return numValue;
  }

  // Default to string
  return value;
}

/**
 * Parses a single line of CSV, respecting quoted fields
 */
function parseCSVLine(
  line: string,
  delimiter: string = ",",
  quote: string = '"'
): string[] {
  const fields: string[] = [];
  let currentField = "";
  let insideQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quote) {
      if (insideQuotes && line[i + 1] === quote) {
        // Escaped quote (two quotes = one literal quote)
        currentField += quote;
        i += 2;
      } else {
        // Toggle quote state
        insideQuotes = !insideQuotes;
        i++;
      }
    } else if (char === delimiter && !insideQuotes) {
      // Found delimiter outside quotes
      fields.push(currentField);
      currentField = "";
      i++;
    } else {
      currentField += char;
      i++;
    }
  }

  // Push the last field
  fields.push(currentField);

  return fields;
}

/**
 * Main CSV parsing function
 */
export function parseCSV(
  input: string,
  options: CSVOptions = {}
): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const rows: Record<string, any>[] = [];
  const errors: ParseError[] = [];
  let headers: string[] = [];

  // Split input by line separator
  const lines = input.split(lineSeparator);

  // Process lines
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (line.trim() === "") {
      continue;
    }

    try {
      const fields = parseCSVLine(line, delimiter, quote);

      // First non-empty line becomes headers
      if (headers.length === 0) {
        headers = fields;
        continue;
      }

      // Validate row has correct number of columns
      if (fields.length !== headers.length) {
        errors.push({
          row: lineIndex,
          message: `Expected ${headers.length} columns but got ${fields.length}`,
        });
        continue;
      }

      // Create row object with type coercion
      const row: Record<string, any> = {};
      for (let i = 0; i < headers.length; i++) {
        row[headers[i]] = coerceValue(fields[i]);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: lineIndex,
        message: `Error parsing line: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  // Create result object with methods
  const result: CSVResult = {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          total += value;
        }
      }
      return total;
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let total = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          total += value;
          count++;
        }
      }

      if (count === 0) {
        return 0;
      }

      return total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      const groups = new Map<any, Record<string, any>[]>();

      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }

      return groups;
    },
  };

  return result;
}

