  console.log('Error Details:');
  for (const error of result.errors) {
    console.log(`Row ${error.row}: ${error.message}`);
  }
}

// Work with valid rows only
console.log(`\nValid user records:`);
for (const row of result.rows) {
  const verified = row.email_verified ? '✓' : '✗';
  console.log(`${verified} ${row.name} (${row.email})`);
}

// Analysis of verified users
const verifiedUsers = result.filter(row => row.email_verified === true);
console.log(`\nVerified users: ${verifiedUsers.length}/${result.count()}`);
```

## Example 6: CSV with Custom Delimiters

Working with tab-separated and semicolon-delimited files:

```typescript
// Tab-separated values (TSV)
const tsvData = `id\tname\tage\tcity\tsalary
1\tAlice\t28\tNew York\t95000
2\tBob\t35\tLos Angeles\t85000
3\tCharlie\t42\tChicago\t105000`;

const tsvResult = parseCSV(tsvData, { delimiter: '\t' });

// Semicolon-delimited
const semiCSV = `product;category;price;stock
Laptop;Electronics;999.99;45
Mouse;Accessories;29.99;500
Keyboard;Accessories;79.99;150`;

const semicResult = parseCSV(semiCSV, { delimiter: ';' });

console.log('TSV Parser:');
