## Example 7: Complex Filtering and Aggregation

Multi-level filtering and custom calculations:

```typescript
const ordersCSV = `
order_id,customer_name,product,quantity,unit_price,order_date,status
O001,John Smith,"Laptop Pro",1,1299.99,2024-01-01,shipped
O002,Jane Doe,"Mouse",5,29.99,2024-01-02,shipped
O003,Bob Johnson,"Keyboard",3,79.99,2024-01-03,processing
O004,Alice Chen,"Monitor",2,599.99,2024-01-04,shipped
O005,John Smith,"USB Cable",10,9.99,2024-01-05,pending
O006,Charlie Brown,"Laptop Pro",1,1299.99,2024-01-06,cancelled
`;

const result = parseCSV(ordersCSV);

// Revenue by status
const statusGroups = result.groupBy('status');
console.log('Revenue by Order Status:');
for (const [status, orders] of statusGroups) {
  const revenue = orders.reduce((sum, o) => 
    sum + (o.quantity * o.unit_price), 0
  );
  console.log(`${status}: ${orders.length} orders, $${revenue.toFixed(2)}`);
}

// Customer analysis
const byCustomer = result.groupBy('customer_name');
console.log('\nCustomer Order Summary:');
for (const [customer, orders] of byCustomer) {
  const total = orders.reduce((sum, o) => sum + (o.quantity * o.unit_price), 0);
  const shipped = orders.filter(o => o.status === 'shipped').length;
  console.log(`${customer}: ${orders.length} orders (${shipped} shipped), $${total.toFixed(2)}`);
}

// Products by popularity
const byProduct = result.groupBy('product');
console.log('\nProduct Popularity:');
const products = Array.from(byProduct.entries())
  .sort((a, b) => 
    b[1].reduce((s, o) => s + o.quantity, 0) - 
    a[1].reduce((s, o) => s + o.quantity, 0)
  );

for (const [product, orders] of products) {
  const totalQty = orders.reduce((s, o) => s + o.quantity, 0);
  console.log(`${product}: ${totalQty} units sold (${orders.length} orders)`);
}

// Large orders (total value > $500)
const largeOrders = result.filter(order => {
  const total = order.quantity * order.unit_price;
  return total > 500;
});
console.log(`\nLarge orders (>$500): ${largeOrders.length}`);
```

## Example 8: Data Validation and Reporting

Validate data and generate reports:

```typescript
const productsCSV = `
sku,name,category,price,stock,is_active
SKU001,"Widget A","Tools",19.99,100,true
SKU002,"Gadget B","Electronics",49.99,null,true
SKU003,"Component C","Parts",9.99,-5,false
SKU004,"Device D","Electronics",99.99,0,true
SKU005,"Tool E","Tools",29.99,250,true
`;

const result = parseCSV(productsCSV);

// Validation report
console.log('Product Validation Report:');
console.log(`Total Products: ${result.count()}\n`);

const issues = [];

for (const product of result.rows) {
  if (product.stock === null) {
    issues.push(`${product.sku}: Missing stock information`);
  }
  if (product.stock < 0) {
    issues.push(`${product.sku}: Negative stock (${product.stock})`);
  }
  if (product.price <= 0) {
    issues.push(`${product.sku}: Invalid price ($${product.price})`);
  }
}

if (issues.length > 0) {
  console.log('Issues Found:');
  for (const issue of issues) {
    console.log(`⚠ ${issue}`);
  }
} else {
  console.log('✓ All products valid');
}

// Active products analysis
const activeProducts = result.filter(p => p.is_active === true);
console.log(`\nActive Products: ${activeProducts.length}`);

const totalInventory = activeProducts.reduce((sum, p) => {
  return sum + (p.stock || 0);
}, 0);

const inventoryValue = activeProducts.reduce((sum, p) => {
  return sum + ((p.stock || 0) * (p.price || 0));
}, 0);

console.log(`Total Units in Stock: ${totalInventory}`);
console.log(`Total Inventory Value: $${inventoryValue.toFixed(2)}`);

// Price statistics
const prices = activeProducts.map(p => p.price);
const avgPrice = prices.reduce((a, b) => a + b) / prices.length;
console.log(`Average Product Price: $${avgPrice.toFixed(2)}`);
```

## Example 9: Time Series Data

Process date-based data:

```typescript
const weatherCSV = `
date,temperature,humidity,wind_speed,condition
2024-01-01,32.5,65,12.3,cloudy
2024-01-02,35.2,58,8.9,sunny
2024-01-03,28.1,75,15.6,rainy
2024-01-04,30.8,62,10.2,cloudy
2024-01-05,38.5,45,5.1,sunny
2024-01-06,25.3,80,18.7,rainy
2024-01-07,31.2,68,9.5,cloudy
`;

const result = parseCSV(weatherCSV);

// Temperature statistics
const avgTemp = result.average('temperature');
const maxTemp = Math.max(...result.rows.map(r => r.temperature));
const minTemp = Math.min(...result.rows.map(r => r.temperature));

console.log('Temperature Summary:');
console.log(`Average: ${avgTemp.toFixed(1)}°F`);
console.log(`Maximum: ${maxTemp.toFixed(1)}°F`);
console.log(`Minimum: ${minTemp.toFixed(1)}°F`);

// Weather conditions frequency
const byCondition = result.groupBy('condition');
console.log('\nWeather Conditions:');
for (const [condition, days] of byCondition) {
  const pct = (days.length / result.count() * 100).toFixed(1);
  console.log(`${condition}: ${days.length} days (${pct}%)`);
}

// High humidity days
const humid = result.filter(day => day.humidity > 70);
console.log(`\nHigh Humidity Days (>70%): ${humid.length}`);

// Windy days
const windy = result.filter(day => day.wind_speed > 12);
console.log(`Windy Days (>12 mph): ${windy.length}`);
```

## Example 10: Multi-Column Aggregations

Complex aggregations across multiple fields:

```typescript
const transactionsCSV = `
id,user_id,user_name,category,amount,fee,date
1,U001,Alice,grocery,45.50,0.45,2024-01-01
2,U002,Bob,electronics,299.99,3.00,2024-01-01
3,U001,Alice,grocery,28.75,0.29,2024-01-02
4,U003,Charlie,clothing,85.00,0.85,2024-01-02
5,U002,Bob,grocery,62.30,0.62,2024-01-03
6,U001,Alice,electronics,199.99,2.00,2024-01-03
7,U003,Charlie,grocery,35.00,0.35,2024-01-04
`;

const result = parseCSV(transactionsCSV);

// Total transaction value (after fees)
const grossAmount = result.sum('amount');
const totalFees = result.sum('fee');
const netAmount = grossAmount - totalFees;

console.log('Transaction Summary:');
console.log(`Gross: $${grossAmount.toFixed(2)}`);
console.log(`Fees: $${totalFees.toFixed(2)}`);
console.log(`Net: $${netAmount.toFixed(2)}`);

// User analysis
const byUser = result.groupBy('user_id');
console.log('\nUser Statistics:');
for (const [userId, txns] of byUser) {
  const userName = txns[0].user_name;
  const totalSpent = txns.reduce((s, t) => s + t.amount, 0);
  const totalFees = txns.reduce((s, t) => s + t.fee, 0);
  console.log(`${userName}: ${txns.length} transactions, $${totalSpent.toFixed(2)} (net: $${(totalSpent - totalFees).toFixed(2)})`);
}

// Category breakdown
const byCategory = result.groupBy('category');
console.log('\nSpending by Category:');
for (const [category, txns] of byCategory) {
  const total = txns.reduce((s, t) => s + t.amount, 0);
  const avgTxn = result.average('amount');
  console.log(`${category}: $${total.toFixed(2)} (${txns.length} transactions)`);
}

// Highest transaction
const highest = result.rows.reduce((max, t) => 
  t.amount > max.amount ? t : max
);
console.log(`\nLargest Transaction: $${highest.amount.toFixed(2)} by ${highest.user_name}`);
```

---

These examples demonstrate the CSV parser's versatility for real-world data processing tasks including analytics, validation, aggregation, and reporting.

