## Configuration Examples

```typescript
// Default comma delimiter
const result1 = parseCSV(csv);

// Semicolon delimiter (common in European CSVs)
const result2 = parseCSV(csv, { delimiter: ';' });

// Tab delimiter
const result3 = parseCSV(csv, { delimiter: '\t' });

// Pipe delimiter
const result4 = parseCSV(csv, { delimiter: '|' });

// Custom quote character
const result5 = parseCSV(csv, { quote: "'" });

// Custom line separator (for data with \r\n)
const result6 = parseCSV(csv, { lineSeparator: '\r\n' });

// All custom options together
const result7 = parseCSV(csv, {
  delimiter: ';',
  quote: "'",
  lineSeparator: '\r\n'
});
```

## Chaining Operations

```typescript
const result = parseCSV(csv);

// Chain multiple operations
const youngerThan30 = result.filter(r => r.age < 30);
const activeYoung = result
  .filter(r => r.age < 30)
  .filter(r => r.active === true);

// Use with array methods
const names = result.rows
  .filter(r => r.active === true)
  .map(r => r.name);

// Complex calculations
const avgAgeByCity = {};
for (const [city, rows] of result.groupBy('city')) {
  const avg = rows.reduce((s, r) => s + r.age, 0) / rows.length;
  avgAgeByCity[city] = avg;
}
```

## Performance Tips

1. **Small files (<10MB)**: Use as-is, no optimization needed
2. **Medium files (10-100MB)**: Works fine, may take 1-2 seconds
3. **Large files (>100MB)**: Consider streaming or chunking
4. **Repeated operations**: Cache results instead of reparsing

```typescript
// Bad: parsing same data multiple times
const result1 = parseCSV(csv);
const sum1 = result1.sum('price');
const result2 = parseCSV(csv);
const avg2 = result2.average('price');

// Good: parse once, use multiple times
const result = parseCSV(csv);
const sum = result.sum('price');
const avg = result.average('price');
```

## Common Patterns

### Filter and Sum
```typescript
const total = result
  .filter(row => row.category === 'Electronics')
  .reduce((sum, row) => sum + row.price, 0);
```

### Group and Analyze
```typescript
const grouped = result.groupBy('department');
for (const [dept, employees] of grouped) {
  const avgSalary = employees
    .reduce((s, e) => s + e.salary, 0) / employees.length;
  console.log(`${dept}: $${avgSalary}`);
}
```

### Sort Results
```typescript
const sorted = result.rows
  .sort((a, b) => b.score - a.score)
  .slice(0, 10);
```

### Transform Data
```typescript
const transformed = result.rows.map(row => ({
